const nodemailer = require("nodemailer");

const transporter = nodemailer.createTransport({
  service: "gmail",
  auth: {
    user: "infothehimalayans@gmail.com",
    pass: "xmacxwumkotitqew", // 👈 यहाँ देखो, मैंने सारे स्पेस हटा दिए हैं
  },
});

const sendBookingEmail = async (userEmail, hotelName, amount) => {
  try {
    await transporter.sendMail({
      from: '"The Himalayans" <infothehimalayans@gmail.com>',
      to: userEmail,
      subject: "🎉 Booking Confirmed - The Himalayans",
      html: `
        <h1>Booking Successful!</h1>
        <p>Namaste! Your stay at <b>${hotelName}</b> is confirmed.</p>
        <p>Total Amount Paid: <b>₹${amount}</b></p>
        <p>We look forward to hosting you in Uttarkashi!</p>
      `,
    });
    console.log("Email sent successfully!");
  } catch (err) {
    console.error("Email Error:", err);
  }
};

module.exports = { sendBookingEmail };